kubectl patch statefulset elasticsearch -n elasticsearch --type=json -p '[
  {
    "op": "add",
    "path": "/spec/template/spec/initContainers/-",
    "value": {
      "name": "init-keystore",
      "image": "docker.elastic.co/elasticsearch/elasticsearch:8.11.1",
      "command": ["/bin/bash", "-c"],
      "args": ["set -e\nmkdir -p /tmp/ks\nif [ -f /usr/share/elasticsearch/config/elasticsearch.keystore ]; then\n  cp /usr/share/elasticsearch/config/elasticsearch.keystore /tmp/ks/elasticsearch.keystore\nelse\n  ES_PATH_CONF=/tmp/ks /usr/share/elasticsearch/bin/elasticsearch-keystore create -s\nfi\ncat /secure-settings/s3.client.default.access_key | ES_PATH_CONF=/tmp/ks /usr/share/elasticsearch/bin/elasticsearch-keystore add --stdin -f s3.client.default.access_key\ncat /secure-settings/s3.client.default.secret_key | ES_PATH_CONF=/tmp/ks /usr/share/elasticsearch/bin/elasticsearch-keystore add --stdin -f s3.client.default.secret_key\ncp /tmp/ks/elasticsearch.keystore /shared-keystore/elasticsearch.keystore\necho keystore-setup-complete"],
      "volumeMounts": [
        {"name": "shared-keystore", "mountPath": "/shared-keystore"},
        {"name": "es-secure-settings-vol", "mountPath": "/secure-settings", "readOnly": true}
      ]
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {"name": "shared-keystore", "emptyDir": {}}
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {"name": "es-secure-settings-vol", "secret": {"secretName": "es-secure-settings"}}
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {"name": "shared-keystore", "mountPath": "/usr/share/elasticsearch/config/elasticsearch.keystore", "subPath": "elasticsearch.keystore"}
  }
]' 2>&1

