# Fix the broken patch:
# 1. Replace the subPath keystore mount with a staging path mount
# 2. Add command override to copy keystore before starting ES
kubectl patch statefulset elasticsearch -n elasticsearch --type=json -p '[
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/volumeMounts/3",
    "value": {
      "name": "shared-keystore",
      "mountPath": "/keystore-staging",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/command",
    "value": ["/bin/bash", "-c"]
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/args",
    "value": ["cp /keystore-staging/elasticsearch.keystore /usr/share/elasticsearch/config/elasticsearch.keystore 2>/dev/null || true; exec /usr/local/bin/docker-entrypoint.sh eswrapper"]
  }
]' 2>&1

